import React, { useState } from 'react';
import { useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { adminLogin } from '../../redux/authSlice';

export default function AdminLoginPage() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const [form, setForm] = useState({ email:'admin@petalandbloom.in', password:'' });

  const handle = async (e) => {
    e.preventDefault();
    const res = await dispatch(adminLogin(form));
    if (res.meta.requestStatus === 'fulfilled') { toast.success('Welcome, Admin! 🌸'); navigate('/admin'); }
    else toast.error(res.payload || 'Admin login failed');
  };

  return (
    <div style={{ minHeight:'100vh',background:'var(--charcoal)',display:'flex',alignItems:'center',justifyContent:'center',padding:'24px' }}>
      <div style={{ width:'100%',maxWidth:400 }}>
        <div style={{ textAlign:'center',marginBottom:28 }}>
          <div style={{ fontSize:48,marginBottom:10 }}>🔐</div>
          <h1 style={{ fontFamily:'var(--ff-display)',fontSize:32,fontWeight:400,color:'#fff' }}>Admin Portal</h1>
          <p style={{ color:'rgba(255,255,255,.5)',fontSize:13 }}>Petal & Bloom Management</p>
        </div>
        <div style={{ background:'rgba(255,255,255,.05)',border:'1px solid rgba(255,255,255,.1)',borderRadius:20,padding:32 }}>
          <form onSubmit={handle} style={{ display:'grid',gap:14 }}>
            {[['email','Email','text'],['password','Password','password']].map(([k,l,t]) => (
              <div key={k} className="form-group">
                <label style={{ fontSize:12,fontWeight:500,color:'rgba(255,255,255,.7)',marginBottom:5,display:'block' }}>{l}</label>
                <input type={t} value={form[k]} onChange={e => setForm({...form,[k]:e.target.value})} required
                  style={{ width:'100%',padding:'11px 14px',border:'1px solid rgba(255,255,255,.15)',borderRadius:10,fontSize:13,color:'#fff',background:'rgba(255,255,255,.08)',outline:'none' }}/>
              </div>
            ))}
            <button type="submit" style={{ width:'100%',padding:'13px',borderRadius:50,background:'var(--rose)',color:'#fff',border:'none',cursor:'pointer',fontWeight:600,fontSize:15,marginTop:6 }}>
              Login to Dashboard
            </button>
          </form>
          <div style={{ textAlign:'center',marginTop:14,fontSize:11,color:'rgba(255,255,255,.3)' }}>
            Default: admin@petalandbloom.in / admin123 (after running seed)
          </div>
        </div>
      </div>
    </div>
  );
}
